UPDATE wp_posts SET
  post_title = 'Feature Codes: How to Turn 27 SKUs Into 1 Product',
  post_content = '<!-- wp:divi/placeholder -->\n<!-- wp:html --><style>/* === MINIMAL STRUCTURAL RESET (vbNative — Divi modules handle all visual properties) === */\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden;margin:0}\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* ═══ Blog FC Post Content — Custom Elements Only ═══ */\n\n/* Custom list bullets (body layout has no custom bullet styling) */\n.blog-fc-list ul { list-style: none; padding: 0; margin: 16px 0 24px; }\n.blog-fc-list li { padding: 4px 0 4px 24px; position: relative; }\n.blog-fc-list li::before {\n  content: \'\'; position: absolute; left: 0; top: 14px;\n  width: 8px; height: 8px; border-radius: 50%; background: #00AFF0;\n}\n.blog-fc-list li strong { color: #000864; }\n\n/* Data card */\n.blog-fc-data-card {\n  background: #F5F7FA; border-left: 4px solid #00AFF0;\n  border-radius: 0 12px 12px 0; padding: 32px; margin: 32px 0; text-align: center;\n}\n.blog-fc-data-inline { display: flex; align-items: center; justify-content: center; gap: 24px; flex-wrap: wrap; }\n.blog-fc-data-number { font-family: \'Noto Sans\', sans-serif; font-size: 36px; font-weight: 800; color: #000864; }\n.blog-fc-data-arrow { font-size: 32px; color: #00AFF0; font-weight: 700; }\n.blog-fc-data-label { font-family: \'JetBrains Mono\', monospace; font-size: 13px; font-weight: 500; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-top: 16px; }\n\n/* Highlight box */\n.blog-fc-highlight {\n  background: linear-gradient(135deg, #f0f9ff, #e0f2fe);\n  border: 1px solid #bae6fd; border-radius: 12px; padding: 28px 32px; margin: 32px 0;\n}\n.blog-fc-highlight p { font-family: \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.75; color: #333; margin: 0; padding: 0; }\n.blog-fc-highlight strong { color: #000864; }\n\n/* Responsive */\n@media (max-width: 768px) {\n  .blog-fc-data-number { font-size: 28px; }\n}\n@media (max-width: 480px) {\n  .blog-fc-highlight { padding: 20px 24px; }\n  .blog-fc-data-inline { flex-direction: column; gap: 8px; }\n}\n/* ═══ Blog FC Post FAQ ═══ */\n\n/* Accordion card styling */\n.et_pb_post_content .et_pb_toggle {\n  border: 1px solid #e5e7eb;\n  border-radius: 8px;\n  overflow: hidden;\n  margin-bottom: 12px;\n  background: #fff;\n}\n.et_pb_post_content .et_pb_toggle_title {\n  padding: 16px 20px;\n}\n.et_pb_post_content .et_pb_toggle_content {\n  padding: 0 20px 16px;\n}\n.et_pb_post_content .et_pb_toggle_content p {\n  margin: 0;\n  padding: 0;\n}\n\n/* FAQ heading — scoped by accordion proximity */\n.et_pb_post_content .et_pb_accordion ~ .et_pb_text .et_pb_text_inner h2,\n.et_pb_post_content .et_pb_text + .et_pb_accordion { /* structural only */ }\n\n/* Accordion toggle icon contrast */\n.et_pb_post_content .et_pb_toggle::before,\n.et_pb_post_content .et_pb_toggle .et_pb_toggle_title::before { color: #666; }\n\n/* Focus states */\n.et_pb_post_content .et_pb_toggle:focus-within { outline: 2px solid #00AFF0; outline-offset: 2px; }\n.et_pb_post_content .et_pb_toggle_title:focus-visible { outline: 2px solid #00AFF0; outline-offset: 2px; }\n\n/* Responsive */\n@media (max-width: 768px) {\n  .et_pb_post_content .et_pb_toggle_title { min-height: 44px; display: flex; align-items: center; }\n}\n\n/* Reduced motion */\n@media (prefers-reduced-motion: reduce) {\n  .et_pb_post_content .et_pb_toggle { transition: none; }\n}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog FC Content"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"60px","bottom":"80px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening Paragraphs"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Your factory makes a shirt. Three sizes (S, M, L), three colors (red, blue, white), three collar types (V-neck, round, crew). That is 27 separate item codes. Each needs its own Bill of Materials, its own inventory tracking record, its own purchasing rules, its own reorder point. Scale this across a product line of even moderate complexity, and you suddenly have thousands of SKUs managing what is fundamentally the same product with minor variations.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening: SKU multiplication problem"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>This is not a theoretical problem. It is a pattern that repeats across every manufacturing sector that deals with configurable products. Electronics (brand/version/source), apparel (size/color/fabric), solar panels (electrical properties), machinery (dimensions/capacity). The result is an ERP system choked with nearly identical item masters, a warehouse team managing dozens of picking locations for functionally identical products, and a purchasing department juggling hundreds of reorder points that should be consolidated under a single material plan.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening: Cross-industry pattern"}}}}} /-->\n<!-- wp:divi/divider {"divider":{"advanced":{"line":{"desktop":{"value":{"show":"on","color":"#000864","style":"solid","position":"center","weight":"3px"}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Accent Divider"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"48px"}}},"spacing":{"desktop":{"value":{"margin":{"top":"40px","bottom":"40px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"SKU Multiplication Problem"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"SKU Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>The Problem with SKU Multiplication</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: SKU Multiplication"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>When you treat each product variation as a separate item code, several predictable problems emerge. First, <strong>inventory accuracy collapses</strong>. Your system shows zero stock of \\"medium blue V-neck,\\" so production stops waiting for replenishment. Meanwhile, the warehouse has excess inventory of \\"medium blue round-neck\\" sitting unused. The materials are identical. The manufacturing process is identical. But because they are tracked as separate items, the system cannot recognize they are interchangeable for material planning purposes.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Inventory accuracy"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Second, <strong>purchasing becomes exponentially more complex</strong>. Instead of one reorder point for \\"shirt fabric - blue,\\" you now have nine — one for each combination that uses blue fabric. Each variation triggers its own purchase requisition. Each has its own minimum order quantity, lead time buffer, and safety stock calculation. The purchasing team spends more time managing item-level parameters than actually negotiating with suppliers or optimizing order quantities.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Purchasing complexity"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Third, <strong>BOM maintenance becomes a nightmare</strong>. Your supplier changes the thread specification. Now you need to update 27 separate BOMs instead of one. A quality issue requires a material substitution. Again, 27 BOMs. A cost change needs to propagate through the system. 27 records. Every change multiplies across every SKU, and every manual update is an opportunity for error — which means some item codes will inevitably drift out of sync with reality.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: BOM nightmare"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Fourth, <strong>warehouse operations suffer</strong>. Picking errors increase because visually similar items are stored across different locations. Cycle counts take longer because each SKU requires separate verification. Space utilization drops because you cannot consolidate storage — the system treats each variation as a unique item requiring its own bin location.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Warehouse operations"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The goal isn\'t fewer products. It\'s fewer item codes managing more products.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"tablet":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"phone":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Quote: Fewer item codes"}}},"decoration":{"spacing":{"desktop":{"value":{"margin":{"bottom":"32px","top":"32px"}}}}}},"css":{"desktop":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"tablet":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"phone":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"What Feature Codes Do"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Feature Codes Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>What Feature Codes Do</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: What Feature Codes Do"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><a href=\\"/products/erp/\\">DigiWin\'s ERP</a> feature code system solves this by separating the concept of a <strong>product</strong> from the concept of a <strong>variant</strong>. Instead of creating 27 separate item codes, you create one item master with multiple feature dimensions. The system defines the product once — its base BOM, its routing, its cost structure, its purchasing rules — and then layers variant dimensions on top.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Product vs variant"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-list\\"><p>In the shirt example, you would define:</p><ul><li><strong>Feature 1 (Size):</strong> S, M, L</li><li><strong>Feature 2 (Color):</strong> Red, Blue, White</li><li><strong>Feature 3 (Collar):</strong> V-neck, Round, Crew</li></ul></div>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"List: Feature dimensions"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The system treats each combination as a unique variant for inventory tracking, order fulfillment, and warehouse management. When a customer orders \\"medium blue V-neck,\\" the system knows exactly which physical inventory to pick. But for BOM maintenance, purchasing planning, and cost accounting, all 27 variants roll up to a single item master. When you need to update the thread specification, you update one BOM — and it applies to all variants automatically.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Variant tracking"}}}}} /-->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-data-card\\"><div class=\\"blog-fc-data-inline\\"><div><div class=\\"blog-fc-data-number\\">27 SKUs</div></div><div class=\\"blog-fc-data-arrow\\">&rarr;</div><div><div class=\\"blog-fc-data-number\\">1 Item Code</div></div></div><div class=\\"blog-fc-data-label\\">90%+ reduction in item master complexity</div></div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Data Card: 27 SKUs → 1 Item Code"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>This is not just a data organization trick. It fundamentally changes how the system handles material planning. When you run MRP, the system aggregates demand across all feature combinations. If you have orders for 100 red shirts (across all sizes and collars) and 50 blue shirts (across all sizes and collars), MRP calculates fabric requirements at the color level — not at the individual SKU level. The result is consolidated purchase requisitions, more accurate reorder points, and fewer stockouts caused by artificial fragmentation of demand.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: MRP aggregation"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Product vs Inventory Features"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Features Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Product Features vs Inventory Features</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: Product vs Inventory"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>DigiWin\'s feature code architecture includes a critical distinction: <strong>product features</strong> (attributes of the product itself) versus <strong>inventory features</strong> (attributes of how you track it). This separation unlocks capabilities that most ERP systems cannot support.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Feature distinction"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Product features are inherent to what you are making. Size, color, electrical rating, material grade — these are choices your customer makes when placing an order, and they often affect the BOM or routing. Inventory features, by contrast, are internal tracking dimensions that the customer never sees. Supplier brand (when multiple suppliers provide functionally identical components), customer-dedicated stock (when a large customer requires segregated inventory), lot number (for traceability without creating separate item codes), warehouse location (when the same product is stocked in multiple facilities) — these are all inventory features.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Feature types explained"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The power of this separation is that you can add inventory tracking complexity without exploding your item master. Consider a scenario: you manufacture solar panels, and you source the same photovoltaic cell from three different suppliers. The cells are functionally identical, but you need to track which supplier\'s material went into each finished panel for warranty traceability.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Solar panel example"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>In a traditional ERP, you would be forced to create three separate item codes for the same cell — one per supplier — and then three separate BOMs for the solar panel. With inventory features, you define one item code for the cell and add \\"supplier brand\\" as an inventory feature. The BOM references a single component. During production, the system tracks which supplier\'s inventory was issued — providing full traceability without fragmenting the item master.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Inventory feature solution"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Real-World Applications"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Applications Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Real-World Applications Across Industries</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: Real-World Applications"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Electronics Manufacturing:</strong> A factory produces power adapters in multiple voltage ratings (12V, 24V, 48V), multiple connector types (USB-C, barrel jack, terminal block), and sources components from multiple suppliers. Without feature codes, this requires dozens of item codes. With feature codes, one item master with three product features and one inventory feature. BOM maintenance effort drops by 80%.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Electronics"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Apparel and Textiles:</strong> A garment manufacturer produces workwear in 5 sizes, 6 colors, and 3 fabric weights. Traditional approach: 90 SKUs. Feature code approach: 1 item code with 3 product features. When a fabric supplier changes, one BOM update instead of 90.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Apparel"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Industrial Components:</strong> A machining shop makes steel brackets in 8 lengths and 4 hole-pattern configurations. Each bracket can be supplied in raw steel or zinc-plated. Traditional approach: 64 SKUs. Feature code approach: 1 item code with 3 features.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Industrial"}}}}} /-->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-highlight\\"><p><strong>Feature-aware costing:</strong> DigiWin\'s feature code system supports cost differentiation at the feature level. If zinc-plated brackets cost more than raw steel (due to the plating process), you can assign incremental cost to the \\"plating\\" feature value without creating separate item codes. The system calculates the final product cost by summing the base item cost plus feature-specific cost adders — giving you variant-level cost accuracy without variant-level item master complexity.</p></div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Highlight: Feature-Aware Costing"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Real Impact"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Impact Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>The Real Impact</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: The Real Impact"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The benefits of feature codes extend far beyond reducing the number of rows in your item master table. The operational impacts touch nearly every function in a manufacturing organization.</p><p><strong>Product setup speed increases dramatically.</strong> Launching a new product with multiple variants no longer requires creating dozens of item codes, BOMs, and routing records. You define one item master, specify feature dimensions, and the system generates all valid combinations automatically.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Product setup speed"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>BOM maintenance errors drop.</strong> When a material specification changes, you update one BOM instead of dozens. Fewer update points means fewer opportunities for data entry errors and fewer instances where some SKUs drift out of sync with others.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: BOM errors"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Inventory visibility improves.</strong> Instead of seeing fragmented stock across dozens of SKUs, planners see consolidated inventory at the feature level. If total blue fabric inventory is sufficient but distributed across multiple combinations, the system recognizes that and avoids unnecessary purchase orders.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Inventory visibility"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Purchasing becomes simpler and more effective.</strong> MRP generates consolidated demand for materials common across feature combinations. Purchase requisitions aggregate by supplier and material, not by individual SKU — increasing order quantities, reducing administrative overhead, and improving supplier relationships.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Purchasing"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Warehouse operations become more efficient.</strong> Cycle counting is faster because feature-coded items can be counted at the aggregate level. Picking accuracy improves because visually similar items are no longer scattered across dozens of bin locations. Storage consolidation becomes possible.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Warehouse"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Feature codes don\'t just reduce SKU count. They restructure how the entire system thinks about product complexity — from planning to purchasing to production to warehouse management.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"tablet":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"phone":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Quote: System restructuring"}}},"decoration":{"spacing":{"desktop":{"value":{"margin":{"bottom":"32px","top":"32px"}}}}}},"css":{"desktop":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"tablet":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"phone":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"What This Means"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Factory Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>What This Means for Your Factory</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: What This Means"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>If your factory produces configurable products — anything with size, color, voltage, dimension, or material variations — you are almost certainly managing more SKUs than necessary. The question is not whether feature codes would help. The question is how much operational overhead you are currently tolerating because your ERP lacks this capability.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Diagnostic intro"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Here is a straightforward diagnostic: count how many item codes in your system share 90%+ identical BOMs, differing only in a single component or dimension. If that number is in the dozens, you have SKU multiplication. If it is in the hundreds, you have SKU explosion. And if your team is maintaining separate spreadsheets to track which items are \\"really the same product,\\" you have already built a feature code system manually — you just do not have software support for it.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Diagnostic"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>DigiWin\'s T100 ERP supports feature codes as a core architectural capability, not an add-on module. This means the entire system — from sales order entry to production planning to inventory management to costing — understands and respects feature-level logic. You are not working around the system. You are working with it.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"16px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: T100 positioning"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog FC FAQ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"60px","bottom":"60px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}},"background":{"desktop":{"value":{"color":"#f8fafc"}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"800px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Frequently Asked Questions</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"700","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"700","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"700","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Heading"}}},"decoration":{"spacing":{"desktop":{"value":{"margin":{"bottom":"32px"}}}}}}} /-->\n<!-- wp:divi/accordion {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Accordion"}}}},"title":{"decoration":{"font":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","size":"17px","color":"#000864"}}}}}},"content":{"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"400","size":"15px","lineHeight":"1.7em","color":"#333333"}}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/accordion-item {"title":{"innerContent":{"desktop":{"value":"What are feature codes in ERP?"}}},"content":{"innerContent":{"desktop":{"value":"<p>Feature codes are a product configuration system built into DigiWin\'s ERP that separates the concept of a product from the concept of a variant. Instead of creating a separate item code for every combination of size, color, material, or specification, you define one item master with multiple feature dimensions. The system manages the base BOM, routing, cost structure, and purchasing rules once, then layers variant dimensions on top — drastically reducing item master complexity while preserving full inventory tracking at the variant level.</p>"}}},"builderVersion":"5.0.0-public-beta.8","module":{"advanced":{"open":{"desktop":{"value":"on"}}},"meta":{"adminLabel":{"desktop":{"value":"FAQ: What are feature codes?"}}}}} /-->\n<!-- wp:divi/accordion-item {"title":{"innerContent":{"desktop":{"value":"How do feature codes reduce SKU count?"}}},"content":{"innerContent":{"desktop":{"value":"<p>Feature codes eliminate SKU multiplication by managing product variations as dimensions of a single item rather than separate item codes. For example, a product with 3 sizes, 3 colors, and 3 collar types would traditionally require 27 separate SKUs, each with its own BOM, inventory record, and purchasing rules. With feature codes, this becomes 1 item code with 3 feature dimensions. BOM maintenance effort drops dramatically — when a material specification changes, you update one BOM instead of 27. MRP also aggregates demand across all feature combinations, producing consolidated purchase requisitions instead of fragmented ones.</p>"}}},"builderVersion":"5.0.0-public-beta.8","module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: How reduce SKU count?"}}}}} /-->\n<!-- wp:divi/accordion-item {"title":{"innerContent":{"desktop":{"value":"What is the difference between product features and inventory features?"}}},"content":{"innerContent":{"desktop":{"value":"<p>Product features are attributes inherent to what you are making — size, color, electrical rating, material grade — that your customer selects when placing an order and that may affect the BOM or routing. Inventory features are internal tracking dimensions the customer never sees, such as supplier brand (when multiple suppliers provide identical components), customer-dedicated stock, lot numbers for traceability, or warehouse location. This separation lets you add inventory tracking complexity for traceability and compliance without exploding your item master or creating duplicate BOMs.</p>"}}},"builderVersion":"5.0.0-public-beta.8","module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: Product vs inventory features?"}}}}} /-->\n<!-- /wp:divi/accordion -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100802;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100802 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100802, '_et_pb_custom_css', '/* === MINIMAL STRUCTURAL RESET (vbNative — Divi modules handle all visual properties) === */\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden;margin:0}\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* ═══ Blog FC Post Content — Custom Elements Only ═══ */\n\n/* Custom list bullets (body layout has no custom bullet styling) */\n.blog-fc-list ul { list-style: none; padding: 0; margin: 16px 0 24px; }\n.blog-fc-list li { padding: 4px 0 4px 24px; position: relative; }\n.blog-fc-list li::before {\n  content: \'\'; position: absolute; left: 0; top: 14px;\n  width: 8px; height: 8px; border-radius: 50%; background: #00AFF0;\n}\n.blog-fc-list li strong { color: #000864; }\n\n/* Data card */\n.blog-fc-data-card {\n  background: #F5F7FA; border-left: 4px solid #00AFF0;\n  border-radius: 0 12px 12px 0; padding: 32px; margin: 32px 0; text-align: center;\n}\n.blog-fc-data-inline { display: flex; align-items: center; justify-content: center; gap: 24px; flex-wrap: wrap; }\n.blog-fc-data-number { font-family: \'Noto Sans\', sans-serif; font-size: 36px; font-weight: 800; color: #000864; }\n.blog-fc-data-arrow { font-size: 32px; color: #00AFF0; font-weight: 700; }\n.blog-fc-data-label { font-family: \'JetBrains Mono\', monospace; font-size: 13px; font-weight: 500; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-top: 16px; }\n\n/* Highlight box */\n.blog-fc-highlight {\n  background: linear-gradient(135deg, #f0f9ff, #e0f2fe);\n  border: 1px solid #bae6fd; border-radius: 12px; padding: 28px 32px; margin: 32px 0;\n}\n.blog-fc-highlight p { font-family: \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.75; color: #333; margin: 0; padding: 0; }\n.blog-fc-highlight strong { color: #000864; }\n\n/* Responsive */\n@media (max-width: 768px) {\n  .blog-fc-data-number { font-size: 28px; }\n}\n@media (max-width: 480px) {\n  .blog-fc-highlight { padding: 20px 24px; }\n  .blog-fc-data-inline { flex-direction: column; gap: 8px; }\n}\n/* ═══ Blog FC Post FAQ ═══ */\n\n/* Accordion card styling */\n.et_pb_post_content .et_pb_toggle {\n  border: 1px solid #e5e7eb;\n  border-radius: 8px;\n  overflow: hidden;\n  margin-bottom: 12px;\n  background: #fff;\n}\n.et_pb_post_content .et_pb_toggle_title {\n  padding: 16px 20px;\n}\n.et_pb_post_content .et_pb_toggle_content {\n  padding: 0 20px 16px;\n}\n.et_pb_post_content .et_pb_toggle_content p {\n  margin: 0;\n  padding: 0;\n}\n\n/* FAQ heading — scoped by accordion proximity */\n.et_pb_post_content .et_pb_accordion ~ .et_pb_text .et_pb_text_inner h2,\n.et_pb_post_content .et_pb_text + .et_pb_accordion { /* structural only */ }\n\n/* Accordion toggle icon contrast */\n.et_pb_post_content .et_pb_toggle::before,\n.et_pb_post_content .et_pb_toggle .et_pb_toggle_title::before { color: #666; }\n\n/* Focus states */\n.et_pb_post_content .et_pb_toggle:focus-within { outline: 2px solid #00AFF0; outline-offset: 2px; }\n.et_pb_post_content .et_pb_toggle_title:focus-visible { outline: 2px solid #00AFF0; outline-offset: 2px; }\n\n/* Responsive */\n@media (max-width: 768px) {\n  .et_pb_post_content .et_pb_toggle_title { min-height: 44px; display: flex; align-items: center; }\n}\n\n/* Reduced motion */\n@media (prefers-reduced-motion: reduce) {\n  .et_pb_post_content .et_pb_toggle { transition: none; }\n}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

